previewCss:
.darma-loader-darma-custom-223 {
  color: var(--loader-color, #f97316);
  width: calc(72px / cos(45deg));
  height: 14px;
  --c: currentColor 0 15px,#0000 0 20px;
  background: 
    repeating-linear-gradient(135deg,var(--c)) left top,
    repeating-linear-gradient( 45deg,var(--c)) left bottom;
  background-size:  200% 50%;
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-223-l4 2s infinite linear;
}
@keyframes darma-loader-darma-custom-223-l4 {
    100% {background-position:top right,bottom right}
}

